#include <bits/stdc++.h>
using namespace std;
int di[4][2]={{0,1},{1,0},{0,-1},{-1,0}};
int n,m,t,sx,sy,fx,fy,ans;
bool b[10][10],to[10][10];
void dfs(int x,int y){
    if(x==fx && y==fy){
        ans++;
        return;
    }
    for(int i=0;i<4;i++){
        int xx=x+di[i][0],yy=y+di[i][1];
        if(xx>0 && yy>0 && xx<=n && yy<=m && !b[xx][yy] && !to[xx][yy])
            to[xx][yy]=1,dfs(xx,yy),to[xx][yy]=0;
    }
}
int main(){
    scanf("%d%d%d%d%d%d%d",&n,&m,&t,&sx,&sy,&fx,&fy);
    for(int i=1;i<=t;i++){
        int x,y;
        scanf("%d%d",&x,&y);
        b[x][y]=1;
    }
    to[sx][sy]=1;
    dfs(sx,sy);
    printf("%d",ans);
    return 0;
}
